#!/usr/bin/env python3
"""
Network Configuration Checker

This script detects the operating system and retrieves network interface configuration.
Supports Windows, Linux, and macOS.
"""

import platform
import subprocess
import sys
import json
from typing import Dict, List, Optional

def get_os_type() -> str:
    """Determine the current operating system."""
    system = platform.system().lower()
    if 'windows' in system:
        return 'windows'
    elif 'linux' in system or 'darwin' in system:
        return 'unix'
    else:
        return 'unknown'

def run_command(command: List[str]) -> Optional[str]:
    """Execute a shell command and return its output."""
    try:
        result = subprocess.run(
            command,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            check=True
        )
        return result.stdout.strip()
    except subprocess.CalledProcessError as e:
        print(f"Command failed: {' '.join(command)}", file=sys.stderr)
        print(f"Error: {e.stderr}", file=sys.stderr)
        return None

def parse_ipconfig_output(output: str) -> List[Dict[str, str]]:
    """Parse ipconfig /all output into structured data."""
    interfaces = []
    lines = output.splitlines()
    current_interface = {}

    for line in lines:
        line = line.strip()
        if not line:
            continue

        # Detect interface name (starts with uppercase and ends with colon)
        if ':' in line and any(c.isupper() for c in line):
            if current_interface:
                interfaces.append(current_interface)
            current_interface = {'name': line.split(':')[0].strip()}
        elif 'IPv4 Address' in line:
            addr = line.split(':')[-1].strip()
            current_interface['ipv4'] = addr
        elif 'Subnet Mask' in line:
            mask = line.split(':')[-1].strip()
            current_interface['subnet_mask'] = mask
        elif 'Default Gateway' in line:
            gw = line.split(':')[-1].strip()
            current_interface['gateway'] = gw
        elif 'DNS Servers' in line:
            dns = line.split(':')[-1].strip()
            current_interface['dns_servers'] = dns.split(', ')

    if current_interface:
        interfaces.append(current_interface)
    return interfaces

def parse_unix_output(output: str, tool: str) -> List[Dict[str, str]]:
    """Parse ifconfig or ip addr show output."""
    interfaces = []
    lines = output.splitlines()
    current_interface = None

    for line in lines:
        line = line.strip()
        if not line:
            continue

        # Interface name detection
        if line and not line.startswith(' ') and not line.startswith('inet'):
            parts = line.split()
            if len(parts) >= 1:
                current_interface = {
                    'name': parts[0],
                    'ipv4': '',
                    'subnet_mask': '',
                    'gateway': '',
                    'dns_servers': []
                }
        elif current_interface and line.startswith('inet '):
            # Parse IPv4 address and subnet mask
            parts = line.split()
            if len(parts) >= 2:
                addr_part = parts[1]
                if '/' in addr_part:
                    current_interface['ipv4'] = addr_part.split('/')[0]
                    current_interface['subnet_mask'] = addr_part.split('/')[1]
        elif current_interface and line.startswith('inet6 '):
            # Handle IPv6 if needed
            pass  # Could be extended for IPv6 support

    if current_interface:
        interfaces.append(current_interface)
    return interfaces

def get_network_info() -> Dict[str, any]:
    """Main function to retrieve network configuration."""
    os_type = get_os_type()
    result = {
        'os': os_type,
        'interfaces': [],
        'timestamp': __import__('datetime').datetime.now().isoformat()
    }

    if os_type == 'windows':
        output = run_command(['ipconfig', '/all'])
        if output:
            result['interfaces'] = parse_ipconfig_output(output)
    elif os_type == 'unix':
        # Try 'ip' command first (modern systems), fallback to 'ifconfig'
        output = run_command(['ip', 'addr', 'show'])
        if not output:
            output = run_command(['ifconfig'])
            tool = 'ifconfig'
        else:
            tool = 'ip'

        if output:
            result['interfaces'] = parse_unix_output(output, tool)
    else:
        print(f"Unsupported OS: {os_type}", file=sys.stderr)

    return result

def main():
    """Entry point for script execution."""
    config = get_network_info()
    print(json.dumps(config, indent=2))

if __name__ == '__main__':
    main()

